using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    // --- CreateOrder ---

    [TestMethod]
    public void CreateOrder_WithValidItems_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = CreateItems(("Widget", 10.00m, 2), ("Gadget", 25.50m, 1));

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.IsNotNull(order);
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(45.50m, order.Total);
        Assert.AreEqual(2, order.Items.Count);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_AssignsNonEmptyId()
    {
        var items = CreateItems(("Widget", 5.00m, 1));

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_WithValidItems_SetsCreatedAtToUtcNow()
    {
        var items = CreateItems(("Widget", 5.00m, 1));
        var before = DateTime.UtcNow;

        var order = _service.CreateOrder("cust-1", items);

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after);
    }

    [TestMethod]
    public void CreateOrder_WithSingleItem_CalculatesTotalCorrectly()
    {
        var items = CreateItems(("Widget", 7.50m, 4));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(30.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 5.00m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
        Assert.AreEqual("Cannot create an order with no items.", ex.Message);
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_ExistingOrder_ReturnsOrder()
    {
        var items = CreateItems(("Widget", 5.00m, 1));
        var created = _service.CreateOrder("cust-1", items);

        var found = _service.GetOrder(created.Id);

        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistingId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_WithOrders_ReturnsMatchingOrders()
    {
        _service.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
        _service.CreateOrder("cust-1", CreateItems(("B", 2m, 1)));
        _service.CreateOrder("cust-2", CreateItems(("C", 3m, 1)));

        var orders = _service.GetOrdersByCustomer("cust-1");

        Assert.AreEqual(2, orders.Count);
    }

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var orders = _service.GetOrdersByCustomer("no-such-customer");

        Assert.IsNotNull(orders);
        Assert.AreEqual(0, orders.Count);
    }

    // --- Data-driven: total calculation ---

    [TestMethod]
    [DynamicData(nameof(TotalCalculationData))]
    public void CreateOrder_VariousItems_CalculatesExpectedTotal(
        string description, List<OrderItem> items, decimal expectedTotal)
    {
        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual(expectedTotal, order.Total);
    }

    public static IEnumerable<(string description, List<OrderItem> items, decimal expectedTotal)> TotalCalculationData =>
    [
        ("Single item qty 1",
            [new() { ProductName = "A", Price = 10m, Quantity = 1 }], 10m),
        ("Single item qty 3",
            [new() { ProductName = "B", Price = 5m, Quantity = 3 }], 15m),
        ("Multiple items",
            [new() { ProductName = "C", Price = 10m, Quantity = 2 },
             new() { ProductName = "D", Price = 3m, Quantity = 5 }], 35m),
        ("Zero price item",
            [new() { ProductName = "Free", Price = 0m, Quantity = 10 }], 0m),
    ];
}

